#include <vector>
#include <algorithm>
#include <cmath>

long long solve(std::vector<long long> nums) {
    long long total_sum_x = 0;
    int n = nums.size();

    if (n <= 1) {
        return 0;
    }

    // The minimum sum of x required is the sum of all positive differences nums[i] - nums[i+1].
    // This represents the total amount that nums[i+1] needs to be increased relative to nums[i]
    // across all adjacent pairs where a violation occurs.
    for (int i = 0; i < n - 1; ++i) {
        if (nums[i] > nums[i+1]) {
            long long difference = nums[i] - nums[i+1];
            total_sum_x += difference;
        }
    }

    return total_sum_x;
}

