#include <vector>
#include <algorithm>
#include <cmath>

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n <= 1) {
        return 0;
    }

    // L_i is the minimum required total increase at index i.
    // We use L_prev to track L_i, initialized to L_0 = 0.
    long long L_prev = 0;
    long long total_cost = 0;

    // We iterate from i=0 up to n-2, calculating L_{i+1} based on L_i.
    for (int i = 0; i < n - 1; ++i) {
        // R_i is the required relative increase: R_i = nums[i] - nums[i+1].
        // We require L_{i+1} >= L_i + R_i.
        long long R_i = nums[i] - nums[i+1];

        // Calculate the minimum required L_{i+1}, ensuring it's non-negative.
        long long L_next = std::max(0LL, L_prev + R_i);

        // The cost contribution at this step is the positive increase in L: max(0, L_{i+1} - L_i).
        long long cost_increase = std::max(0LL, L_next - L_prev);

        total_cost += cost_increase;

        // Update L_prev for the next iteration.
        L_prev = L_next;
    }

    return total_cost;
}

