#include <vector>
#include <algorithm>
#include <limits>

long long solve(std::vector<long long> nums) {
    if (nums.empty()) {
        return 0;
    }

    // We are finding the minimum total cost to achieve the sequence B* which is the 
    // smallest non-decreasing sequence such that B*_i >= nums[i].
    // The minimum cost is C = I*_0 + sum(max(0, I*_i - I*_{i-1})), 
    // where I*_i = B*_i - nums[i].

    long long total_cost = 0;

    // B_prev tracks B*_{i-1}. We initialize it to a very small number 
    // so that B*_0 = max(nums[0], B_prev) results in nums[0].
    long long b_prev = std::numeric_limits<long long>::min();

    // I_prev tracks I*_{i-1}. I*_{-1} = 0 conceptually.
    long long i_prev = 0;

    for (size_t i = 0; i < nums.size(); ++i) {
        long long a_i = nums[i];

        // 1. Determine B*_i: The smallest non-decreasing sequence majorizing A
        long long b_current = std::max(a_i, b_prev);

        // 2. Determine I*_i: Required increase
        long long i_current = b_current - a_i;

        // 3. Calculate cost contribution: max(0, I*_i - I*_{i-1})
        // This captures the total amount of new operations that must start at index i.
        long long cost_contrib = std::max(0LL, i_current - i_prev);

        total_cost += cost_contrib;

        // 4. Update previous values for the next iteration
        b_prev = b_current;
        i_prev = i_current;
    }

    return total_cost;
}

